// LESSON: Reference Page 1 - record och enum.
// You will learn: Represent fixed choices and immutable data with enum and record.
class Prog2Reference439 {
  // EXEMPEL 1: enum representerar ett fast antal mojliga varden.
  enum Suit { HEARTS, SPADES, DIAMONDS, CLUBS }
  static boolean isRed(Suit suit) {
    return suit == Suit.HEARTS || suit == Suit.DIAMONDS;
  }
  // EXEMPEL 2: enum kan ha falt, konstruktor och metoder.
  enum Priority {
    LOW(1), MEDIUM(2), HIGH(3);
    private final int weight;
    Priority(int weight) { this.weight = weight; }
    int weight() { return weight; }
  }
  // EXEMPEL 3: record ar en kompakt immutable databarare.
  record Grade(String name, int points) {
    Grade {
      if (points < 0) { throw new IllegalArgumentException("points"); }
    }
  }
  static String display(Grade grade) { return grade.name() + ":" + grade.points(); }
}
